package com.play.emojireactionchain.ui.theme
import androidx.compose.ui.graphics.Color
// Primary Palette val PrimarySoft = Color(0xFF6C63FF) // Playful Purple val SecondarySoft = Color(0xFFFF6584) // Sweet Pink val TertiarySoft = Color(0xFF43D39E) // Fresh Green
// Action Colors val SuccessGreen = Color(0xFF4CAF50) val ErrorRed = Color(0xFFF44336) val WarningOrange = Color(0xFFFF9800) val InfoBlue = Color(0xFF2196F3)
// Background & Surface val SoftBackground = Color(0xFFF8F9FE) // Almost White val SurfaceWhite = Color(0xFFFFFFFF)
// Pastel Mode Colors for Kids val PastelGreen = Color(0xFFE8F5E9) // Normal Mode val PastelBlue = Color(0xFFE3F2FD) // Timed Mode val PastelYellow = Color(0xFFFFFDE7) // Survival Mode val PastelPink = Color(0xFFFCE4EC) // Blitz Mode
// Contrast Colors val TextMain = Color(0xFF2D3243) val TextSecondary = Color(0xFF7A8299) val IconTint = Color(0xFF4A4E69)
val Purple80 = Color(0xFFD0BCFF) val PurpleGrey80 = Color(0xFFCCC2DC) val Pink80 = Color(0xFFEFB8C8)
val Purple40 = Color(0xFF6650a4) val PurpleGrey40 = Color(0xFF625b71) val Pink40 = Color(0xFF7D5260)

