            modifier = Modifier.padding(bottom = 16.dp)
        )

        HomeStatsRow(
            dailyStreak = dailyStreak,
            bestScores = bestScores,
            modifier = Modifier.padding(horizontal = 16.dp)
        )

        LazyVerticalGrid(
            columns = GridCells.Fixed(2),
            modifier = Modifier.padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp),
            horizontalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            item {
                GameModeCard(
                    icon = Icons.Filled.PlayArrow,
                    modeName = stringResource(R.string.mode_normal_name),
                    modeSubtitle = stringResource(R.string.mode_normal_subtitle),
                    cardColor = Color(0xFFA5D6A7),
                    iconTint = Color(0xFF4CAF50)
                ) { onModeSelected(GameMode.NORMAL) }
            }
            item {
                GameModeCard(
                    icon = Icons.Filled.Timer,
                    modeName = stringResource(R.string.mode_timed_name),
                    modeSubtitle = stringResource(R.string.mode_timed_subtitle),
                    cardColor = Color(0xFF90CAF9),
                    iconTint = Color(0xFF2196F3)
                ) { onModeSelected(GameMode.TIMED) }
            }
            item {
                GameModeCard(
                    icon = Icons.Filled.Shield,
                    modeName = stringResource(R.string.mode_survival_name),
                    modeSubtitle = stringResource(R.string.mode_survival_subtitle),
                    cardColor = Color(0xFFFFD54F),
                    iconTint = Color(0xFFFF9800)
                ) { onModeSelected(GameMode.SURVIVAL) }
            }
            item {
                GameModeCard(
                    icon = Icons.Filled.Bolt,
                    modeName = stringResource(R.string.mode_blitz_name),
                    modeSubtitle = stringResource(R.string.mode_blitz_subtitle),
                    cardColor = Color(0xFFF48FB1),
                    iconTint = Color(0xFFE91E63)
                ) { onModeSelected(GameMode.BLITZ) }
            }
        }
    }
}

@Composable
private fun HomeStatsRow(
    dailyStreak: Int,
    bestScores: Map<GameMode, Int>,
    modifier: Modifier = Modifier
) {
    Column(modifier = modifier.fillMaxWidth()) {
        Text(
            text = stringResource(R.string.daily_streak_label) + ": " +
                stringResource(R.string.daily_streak_value, dailyStreak),
            style = MaterialTheme.typography.bodyMedium,
            color = MaterialTheme.colorScheme.onSurface,
            fontWeight = FontWeight.SemiBold,
            modifier = Modifier.padding(bottom = 8.dp)
        )

        Text(
            text = stringResource(R.string.best_scores_label),
            style = MaterialTheme.typography.bodySmall,
            color = MaterialTheme.colorScheme.onSurfaceVariant,
            modifier = Modifier.padding(bottom = 6.dp)
        )

        val modeOrder = listOf(GameMode.NORMAL, GameMode.TIMED, GameMode.SURVIVAL, GameMode.BLITZ)
        LazyRow(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            items(modeOrder) { mode ->
                val shortLabel = stringResource(shortModeLabelRes(mode))
                val score = bestScores[mode] ?: 0
                Card(colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)) {
                    Row(
                        modifier = Modifier.padding(horizontal = 10.dp, vertical = 6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = stringResource(R.string.best_score_item, shortLabel, score),
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            fontWeight = FontWeight.Medium
                        )
                    }
                }
            }
        }
    }
}

private fun shortModeLabelRes(mode: GameMode): Int {
    return when (mode) {
        GameMode.NORMAL -> R.string.mode_short_normal
        GameMode.TIMED -> R.string.mode_short_timed
        GameMode.SURVIVAL -> R.string.mode_short_survival
        GameMode.BLITZ -> R.string.mode_short_blitz
    }
}

@Composable
fun GameModeCard(
    icon: ImageVector,
    modeName: String,
    modeSubtitle: String,
    cardColor: Color,
    iconTint: Color,
    onModeSelected: () -> Unit
) {
    Card(
        onClick = onModeSelected,
        modifier = Modifier.size(165.dp),
        colors = CardDefaults.elevatedCardColors(containerColor = cardColor)
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(14.dp),
            verticalArrangement = Arrangement.Center,
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Icon(
                imageVector = icon,
                contentDescription = modeName,
                modifier = Modifier
                    .size(58.dp)
                    .padding(bottom = 8.dp),
                tint = iconTint
            )
            Text(
                modeName,
                style = MaterialTheme.typography.bodyMedium,
                fontWeight = FontWeight.Bold,
                textAlign = TextAlign.Center,
                color = Color.Black
            )
            Text(
                modeSubtitle,
                style = MaterialTheme.typography.bodySmall,
                textAlign = TextAlign.Center,
                color = Color.Black.copy(alpha = 0.8f),
                modifier = Modifier.padding(top = 4.dp)
            )
        }
    }
}

