@Composable
fun ModeSelectionScreen(
    dailyStreak: Int,
    bestScores: Map<GameMode, Int>,
    onModeSelected: (GameMode) -> Unit
) {
    var showHeader by remember { mutableStateOf(false) }
    LaunchedEffect(Unit) { showHeader = true }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(
                Brush.verticalGradient(
                    colors = listOf(
                        MaterialTheme.colorScheme.background,
                        MaterialTheme.colorScheme.primary.copy(alpha = 0.05f)
                    )
                )
            )
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(24.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Spacer(modifier = Modifier.height(24.dp))

            AnimatedVisibility(visible = showHeader) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text(
                        text = stringResource(R.string.home_title),
                        style = MaterialTheme.typography.headlineLarge.copy(
                            fontWeight = FontWeight.ExtraBold,
                            fontSize = 36.sp,
                            lineHeight = 42.sp
                        ),
                        color = PrimarySoft,
                        textAlign = TextAlign.Center
                    )
                    Text(
                        text = stringResource(R.string.home_subtitle),
                        style = MaterialTheme.typography.bodyLarge.copy(
                            fontWeight = FontWeight.Medium,
                            letterSpacing = 0.5.sp
                        ),
                        color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f),
                        modifier = Modifier.padding(top = 8.dp)
                    )
                }
            }

            Spacer(modifier = Modifier.height(32.dp))

            HomeStatsRowWithStyle(
                dailyStreak = dailyStreak,
                bestScores = bestScores
            )

            Spacer(modifier = Modifier.height(24.dp))

            LazyVerticalGrid(
                columns = GridCells.Fixed(2),
                modifier = Modifier.fillMaxWidth(),
                verticalArrangement = Arrangement.spacedBy(20.dp),
                horizontalArrangement = Arrangement.spacedBy(20.dp)
            ) {
                item {
                    GameModeCardStyled(
                        icon = Icons.Filled.PlayArrow,
                        modeName = stringResource(R.string.mode_normal_name),
                        modeSubtitle = stringResource(R.string.mode_normal_subtitle),
                        cardColor = PastelGreen,
                        accentColor = Color(0xFF43A047),
                        onModeSelected = { onModeSelected(GameMode.NORMAL) }
                    )
                }
                item {
                    GameModeCardStyled(
                        icon = Icons.Filled.Timer,
                        modeName = stringResource(R.string.mode_timed_name),
                        modeSubtitle = stringResource(R.string.mode_timed_subtitle),
                        cardColor = PastelBlue,
                        accentColor = Color(0xFF1E88E5),
                        onModeSelected = { onModeSelected(GameMode.TIMED) }
                    )
                }
                item {
                    GameModeCardStyled(
                        icon = Icons.Filled.Shield,
                        modeName = stringResource(R.string.mode_survival_name),
                        modeSubtitle = stringResource(R.string.mode_survival_subtitle),
                        cardColor = PastelYellow,
                        accentColor = Color(0xFFFBC02D),
                        onModeSelected = { onModeSelected(GameMode.SURVIVAL) }
                    )
                }
                item {
                    GameModeCardStyled(
                        icon = Icons.Filled.Bolt,
                        modeName = stringResource(R.string.mode_blitz_name),
                        modeSubtitle = stringResource(R.string.mode_blitz_subtitle),
                        cardColor = PastelPink,
                        accentColor = SecondarySoft,
                        onModeSelected = { onModeSelected(GameMode.BLITZ) }
                    )
                }
            }
        }
    }
}

@Composable
private fun HomeStatsRowWithStyle(
    dailyStreak: Int,
    bestScores: Map<GameMode, Int>,
    modifier: Modifier = Modifier
) {
    Column(modifier = modifier.fillMaxWidth()) {
        Card(
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = SurfaceWhite),
            modifier = Modifier
                .fillMaxWidth()
                .shadow(8.dp, RoundedCornerShape(24.dp))
        ) {
            Row(
                modifier = Modifier
                    .padding(20.dp)
                    .fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Box(
                    modifier = Modifier
                        .size(56.dp)
                        .background(TertiarySoft.copy(alpha = 0.2f), CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Text("", fontSize = 28.sp)
                }
                Spacer(modifier = Modifier.width(16.dp))
                Column {
                    Text(
                        text = stringResource(R.string.daily_streak_label),
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                    Text(
                        text = stringResource(R.string.daily_streak_value, dailyStreak),
                        style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.Bold),
                        color = TextMain
                    )
                }
            }
        }

        Spacer(modifier = Modifier.height(16.dp))

        Text(
            text = stringResource(R.string.best_scores_label),
            style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
            color = MaterialTheme.colorScheme.onSurfaceVariant,
            modifier = Modifier.padding(start = 8.dp, bottom = 8.dp)
        )

        val modeOrder = listOf(GameMode.NORMAL, GameMode.TIMED, GameMode.SURVIVAL, GameMode.BLITZ)
        LazyRow(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
            items(modeOrder) { mode ->
                val shortLabel = stringResource(shortModeLabelRes(mode))
                val score = bestScores[mode] ?: 0
                Surface(
                    shape = RoundedCornerShape(16.dp),
                    color = MaterialTheme.colorScheme.surface,
                    border = null,
                    modifier = Modifier.shadow(2.dp, RoundedCornerShape(16.dp))
                ) {
                    Row(
                        modifier = Modifier.padding(horizontal = 14.dp, vertical = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Box(
                            modifier = Modifier
                                .size(8.dp)
                                .background(getModeAccent(mode), CircleShape)
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = "$shortLabel: $score",
                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.SemiBold),
                            color = TextMain
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun GameModeCardStyled(
    icon: ImageVector,
    modeName: String,
    modeSubtitle: String,
    cardColor: Color,
    accentColor: Color,
    onModeSelected: () -> Unit
) {
    Card(
        modifier = Modifier
            .height(180.dp)
            .fillMaxWidth()
            .clickable { onModeSelected() }
            .shadow(4.dp, RoundedCornerShape(32.dp)),
        shape = RoundedCornerShape(32.dp),
        colors = CardDefaults.cardColors(containerColor = cardColor)
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(16.dp),
            verticalArrangement = Arrangement.SpaceAround,
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Box(
                modifier = Modifier
                    .size(64.dp)
                    .background(accentColor.copy(alpha = 0.15f), CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = icon,
                    contentDescription = null,
                    modifier = Modifier.size(32.dp),
                    tint = accentColor
                )
            }
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Text(
                    text = modeName,
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = TextMain,
                    textAlign = TextAlign.Center
                )
                Text(
                    text = modeSubtitle,
                    style = MaterialTheme.typography.bodySmall.copy(lineHeight = 14.sp),
                    color = TextMain.copy(alpha = 0.7f),
                    textAlign = TextAlign.Center,
                    modifier = Modifier.padding(top = 4.dp)
                )
            }
        }
    }
}

private fun shortModeLabelRes(mode: GameMode): Int {
    return when (mode) {
        GameMode.NORMAL -> R.string.mode_short_normal
        GameMode.TIMED -> R.string.mode_short_timed
        GameMode.SURVIVAL -> R.string.mode_short_survival
        GameMode.BLITZ -> R.string.mode_short_blitz
    }
}

private fun getModeAccent(mode: GameMode): Color {
    return when (mode) {
        GameMode.NORMAL -> Color(0xFF43A047)
        GameMode.TIMED -> Color(0xFF1E88E5)
        GameMode.SURVIVAL -> Color(0xFFFBC02D)
        GameMode.BLITZ -> SecondarySoft
    }
}

package com.play.emojireactionchain.ui.theme

import android.app.Activity
import android.os.Build
import androidx.compose.foundation.isSystemInDarkTheme
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.darkColorScheme
import androidx.compose.material3.dynamicDarkColorScheme
import androidx.compose.material3.dynamicLightColorScheme
import androidx.compose.material3.lightColorScheme
import androidx.compose.runtime.Composable
import androidx.compose.runtime.SideEffect
import androidx.compose.ui.graphics.toArgb
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.platform.LocalView
import androidx.core.view.WindowCompat

private val DarkColorScheme = darkColorScheme(
    primary = Purple80,
    secondary = PurpleGrey80,
    tertiary = Pink80
)

private val LightColorScheme = lightColorScheme(
    primary = Purple40,
    secondary = PurpleGrey40,
    tertiary = Pink40

    /* Other default colors to override
    background = Color(0xFFFFFBFE),
    surface = Color(0xFFFFFBFE),
    onPrimary = Color.White,
    onSecondary = Color.White,
    onTertiary = Color.White,
    onBackground = Color(0xFF1C1B1F),
    onSurface = Color(0xFF1C1B1F),
    */
)

@Composable
fun EmojiGameTheme(
    darkTheme: Boolean = isSystemInDarkTheme(),
    // Dynamic color is available on Android 12+
    dynamicColor: Boolean = true,
    content: @Composable () -> Unit
) {
    val colorScheme = when {
        dynamicColor && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S -> {
            val context = LocalContext.current
            if (darkTheme) dynamicDarkColorScheme(context) else dynamicLightColorScheme(context)
        }

        darkTheme -> DarkColorScheme
        else -> LightColorScheme
    }
    val view = LocalView.current
    if (!view.isInEditMode) {
        SideEffect {
            val window = (view.context as Activity).window
            window.statusBarColor = colorScheme.primary.toArgb()
            WindowCompat.getInsetsController(window, view).isAppearanceLightStatusBars = darkTheme
        }
    }

    MaterialTheme(
        colorScheme = colorScheme,
        typography = appTypography, // Use appTypography from Type.kt
        content = content
    )
}

package com.play.emojireactionchain.ui.theme

import android.app.Activity
import android.os.Build
import androidx.compose.foundation.isSystemInDarkTheme
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.darkColorScheme
import androidx.compose.material3.dynamicDarkColorScheme
import androidx.compose.material3.dynamicLightColorScheme
import androidx.compose.material3.lightColorScheme
import androidx.compose.runtime.Composable
import androidx.compose.runtime.SideEffect
import androidx.compose.ui.graphics.toArgb
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.platform.LocalView
import androidx.core.view.WindowCompat

private val DarkColorScheme = darkColorScheme(
    primary = Purple80,
    secondary = PurpleGrey80,
    tertiary = Pink80,
    background = Color(0xFF1C1B20),
    surface = Color(0xFF25252A),
    onSurface = Color.White
)

private val LightColorScheme = lightColorScheme(
    primary = PrimarySoft,
    secondary = SecondarySoft,
    tertiary = TertiarySoft,
    background = SoftBackground,
    surface = SurfaceWhite,
    onPrimary = Color.White,
    onSecondary = Color.White,
    onBackground = TextMain,
    onSurface = TextMain
)

@Composable
fun EmojiGameTheme(
    darkTheme: Boolean = isSystemInDarkTheme(),
    // Disable dynamic color by default for a consistent kid-friendly branded look
    dynamicColor: Boolean = false,
    content: @Composable () -> Unit
) {
    val colorScheme = when {
        dynamicColor && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S -> {
            val context = LocalContext.current
            if (darkTheme) dynamicDarkColorScheme(context) else dynamicLightColorScheme(context)
        }

        darkTheme -> DarkColorScheme
        else -> LightColorScheme
    }
    val view = LocalView.current
    if (!view.isInEditMode) {
        SideEffect {
            val window = (view.context as Activity).window
            window.statusBarColor = colorScheme.primary.toArgb()
            WindowCompat.getInsetsController(window, view).isAppearanceLightStatusBars = darkTheme
        }
    }

    MaterialTheme(
        colorScheme = colorScheme,
        typography = appTypography, // Use appTypography from Type.kt
        content = content
    )
}
